# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy.ext.automap import automap_base
import os

app = Flask(__name__)
basedir = os.path.abspath(os.path.dirname('__file__'))
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///' + os.path.join(basedir, 'annotations.db')
db = SQLAlchemy(app)
Base = automap_base()
Base.prepare(db.engine, reflect=True)
Annotations = Base.classes.annotations  # Assuming you have a table named annotations with columns: id, image_id, label

@app.route('/label', methods=['POST'])
def post_label():
    data = request.get_json()
    new_annotation = Annotations(image_id=data['image_id'], label=data['label'])  # Assuming your input JSON has keys: image_id, label
    db.session.add(new_annotation)
    db.session.commit()
    return jsonify({'message': 'New annotation created'}), 201

@app.route('/aggregate', methods=['GET'])
def aggregate():
    image_id = request.args.get('image_id')
    labels = db.session.query(Annotations).filter_by(image_id=image_id).all()  # Get all annotations for a specific image
    label_counts = {}
    for label in labels:
        if label.label not in label_counts:
            label_counts[label.label] = 1
        else:
            label_counts[label.label] += 1  # Count the occurrence of each label
    majority_label = max(label_counts, key=label_counts.get)  # Get the most common label
    return jsonify({'majority_vote': majority_label}), 200

if __name__ == '__main__':
    app.run()